    s = input().strip()
    n = len(s)

    left_smaller = [-1] * n
    stack = []
    for i in range(n):
        while stack and int(s[stack[-1]]) <= int(s[i]):
            stack.pop()
        if stack:
            left_smaller[i] = stack[-1]
        stack.append(i)

    right_not_larger = [n] * n
    stack = []
    for i in range(n - 1, -1, -1):
        while stack and int(s[stack[-1]]) <= int(s[i]):
            stack.pop()
        if stack:
            right_not_larger[i] = stack[-1]
        stack.append(i)

    total_value = 0
    total_count = n * (n + 1) // 2

    for i in range(n):
        val = int(s[i])
        left_boundary = left_smaller[i]
        right_boundary = right_not_larger[i]
        count = (i - left_boundary) * (right_boundary - i)
        total_value += val * count

    avg = Fraction(total_value, total_count)

    whole = avg.numerator // avg.denominator
    remainder = avg.numerator % avg.denominator

    if whole == 0:
        if remainder == 0:
            print(0)
